PROGRAM TankLevelMonitor
VAR_INPUT
    RawLevel : INT;
END_VAR
VAR
    HighAlarmSP : REAL := 85.0;
    LowAlarmSP : REAL := 15.0;
    Hysteresis : REAL := 2.0;
    HighAlarmState : BOOL := FALSE;
    LowAlarmState : BOOL := FALSE;
END_VAR
VAR_OUTPUT
    LevelPct : REAL;
    HighAlarm : BOOL;
    LowAlarm : BOOL;
END_VAR

LevelPct := INT_TO_REAL(RawLevel) / 276.48;

IF LevelPct >= HighAlarmSP THEN
    HighAlarmState := TRUE;
ELSIF LevelPct < (HighAlarmSP - Hysteresis) THEN
    HighAlarmState := FALSE;
END_IF;
HighAlarm := HighAlarmState;

IF LevelPct <= LowAlarmSP THEN
    LowAlarmState := TRUE;
ELSIF LevelPct > (LowAlarmSP + Hysteresis) THEN
    LowAlarmState := FALSE;
END_IF;
LowAlarm := LowAlarmState;

END_PROGRAM

PROGRAM MotorStarDelta
VAR_INPUT
    Start_btn : BOOL;
    Stop_btn : BOOL;
    Overload : BOOL;
END_VAR
VAR_OUTPUT
    Main_Contactor : BOOL;
    Star_Contactor : BOOL;
    Delta_Contactor : BOOL;
    Fault : BOOL;
END_VAR
VAR
    StartEdge : R_TRIG;
    MotorRunning : BOOL := FALSE;
    StarTimer : TON;
END_VAR

StartEdge(CLK := Start_btn);
Fault := Overload;

IF Stop_btn OR Overload THEN
    MotorRunning := FALSE;
    Main_Contactor := FALSE;
    Star_Contactor := FALSE;
    Delta_Contactor := FALSE;
    StarTimer(IN := FALSE);
ELSIF StartEdge.Q AND NOT MotorRunning THEN
    MotorRunning := TRUE;
    Main_Contactor := TRUE;
    Star_Contactor := TRUE;
    Delta_Contactor := FALSE;
    StarTimer(IN := TRUE, PT := T#3S);
ELSIF MotorRunning AND StarTimer.Q THEN
    Star_Contactor := FALSE;
    Delta_Contactor := TRUE;
END_IF;
END_PROGRAM

TYPE ConveyorState :
    (ST_IDLE, ST_RUNNING, ST_REJECTING, ST_FAULT);
END_TYPE

PROGRAM SortingConveyor
VAR_INPUT
    StartCmd : BOOL;
    SensorPresent : BOOL;
    SensorDefect : BOOL;
    EStop : BOOL;
END_VAR
VAR_OUTPUT
    MotorRun : BOOL;
    RejectSolenoid : BOOL;
END_VAR
VAR
    CurrentState : ConveyorState := ST_IDLE;
    RejectTimer : TON;
END_VAR

CASE CurrentState OF
    ST_IDLE:
        MotorRun := FALSE;
        RejectSolenoid := FALSE;
        RejectTimer(IN := FALSE);
        IF EStop THEN
            CurrentState := ST_FAULT;
        ELSIF StartCmd THEN
            CurrentState := ST_RUNNING;
        END_IF;

    ST_RUNNING:
        MotorRun := TRUE;
        RejectSolenoid := FALSE;
        IF SensorPresent AND SensorDefect THEN
            RejectTimer(IN := TRUE, PT := T#500MS);
        ELSE
            RejectTimer(IN := FALSE);
        END_IF;

        IF EStop THEN
            CurrentState := ST_FAULT;
        ELSIF RejectTimer.Q THEN
            CurrentState := ST_REJECTING;
        END_IF;

    ST_REJECTING:
        MotorRun := FALSE;
        RejectSolenoid := TRUE;
        IF EStop THEN
            CurrentState := ST_FAULT;
        ELSIF RejectTimer.Q THEN
            CurrentState := ST_RUNNING;
        END_IF;

    ST_FAULT:
        MotorRun := FALSE;
        RejectSolenoid := FALSE;
        RejectTimer(IN := FALSE);
        IF NOT EStop THEN
            CurrentState := ST_IDLE;
        END_IF;
END_CASE;
END_PROGRAM

