FUNCTION_BLOCK PID_Temperature
VAR_INPUT
    Enable : BOOL;
    Setpoint : REAL;
    ProcessValue : REAL;
    Kp : REAL;
    Ki : REAL;
    Kd : REAL;
    CycleTime : TIME;
END_VAR
VAR_OUTPUT
    Output : REAL;
END_VAR
VAR
    integral : REAL;
    lastError : REAL;
    ts : REAL;
    error : REAL;
    initialized : BOOL := FALSE;
END_VAR

IF NOT initialized THEN
    Kp := 2.0;
    Ki := 0.05;
    Kd := 0.0;
    CycleTime := T#100ms;
    initialized := TRUE;
END_IF;

IF NOT Enable THEN
    Output := 0.0;
    integral := 0.0;
    lastError := 0.0;
ELSE
    ts := TO_REAL(TIME_TO_INT(CycleTime));
    error := Setpoint - ProcessValue;
    integral := integral + error * ts;

    IF ts > 0.0 THEN
        Output := Kp * error + Ki * integral + Kd * (error - lastError) / ts;
    ELSE
        Output := Kp * error + Ki * integral;
    END_IF;

    lastError := error;
END_IF;

Output := LIMIT(0.0, Output, 100.0);

END_FUNCTION_BLOCK
