PROGRAM PumpLeadLag
VAR_INPUT
    LevelLow : BOOL;
    LevelHigh : BOOL;
    Pump1Fault : BOOL;
    Pump2Fault : BOOL;
    ManualMode : BOOL;
    ManualP1Run : BOOL;
    ManualP2Run : BOOL;
END_VAR
VAR_OUTPUT
    P1Run : BOOL;
    P2Run : BOOL;
END_VAR
VAR
    leadPump : INT := 1;
END_VAR

IF ManualMode THEN
    P1Run := ManualP1Run;
    P2Run := ManualP2Run;
ELSE
    IF LevelHigh THEN
        P1Run := FALSE;
        P2Run := FALSE;
    ELSIF LevelLow THEN
        P1Run := FALSE;
        P2Run := FALSE;
        IF leadPump = 1 AND NOT Pump1Fault THEN
            P1Run := TRUE;
        ELSIF leadPump = 2 AND NOT Pump2Fault THEN
            P2Run := TRUE;
        END_IF;
    END_IF;

    IF leadPump = 1 AND Pump1Fault AND NOT Pump2Fault THEN
        leadPump := 2;
    ELSIF leadPump = 2 AND Pump2Fault AND NOT Pump1Fault THEN
        leadPump := 1;
    END_IF;
END_IF;
END_PROGRAM

PROGRAM BatchDoseSequence
VAR_INPUT
    StartSeq : BOOL;
    Abort : BOOL;
END_VAR
VAR_OUTPUT
    Valve1 : BOOL;
    Valve2 : BOOL;
    Valve3 : BOOL;
    SeqDone : BOOL;
    SeqActive : BOOL;
END_VAR
VAR
    Step : INT := 0;
    Timer1 : TON;
    Timer2 : TON;
    Timer3 : TON;
END_VAR
IF Abort THEN
    Step := 0;
    Valve1 := FALSE;
    Valve2 := FALSE;
    Valve3 := FALSE;
    SeqDone := FALSE;
    SeqActive := FALSE;
    Timer1(IN := FALSE, PT := T#2s);
    Timer2(IN := FALSE, PT := T#2s);
    Timer3(IN := FALSE, PT := T#2s);
ELSE
    CASE Step OF
        0:
            Valve1 := FALSE;
            Valve2 := FALSE;
            Valve3 := FALSE;
            SeqActive := FALSE;
            Timer1(IN := FALSE, PT := T#2s);
            Timer2(IN := FALSE, PT := T#2s);
            Timer3(IN := FALSE, PT := T#2s);
            IF StartSeq THEN
                Step := 1;
            END_IF;
        1:
            Valve1 := TRUE;
            Valve2 := FALSE;
            Valve3 := FALSE;
            SeqActive := TRUE;
            Timer1(IN := TRUE, PT := T#2s);
            IF Timer1.Q THEN
                Step := 2;
            END_IF;
        2:
            Valve1 := TRUE;
            Valve2 := TRUE;
            Valve3 := FALSE;
            SeqActive := TRUE;
            Timer2(IN := TRUE, PT := T#3s);
            IF Timer2.Q THEN
                Step := 3;
            END_IF;
        3:
            Valve1 := TRUE;
            Valve2 := TRUE;
            Valve3 := TRUE;
            SeqActive := TRUE;
            Timer3(IN := TRUE, PT := T#1s);
            IF Timer3.Q THEN
                Step := 4;
            END_IF;
        4:
            Valve1 := FALSE;
            Valve2 := FALSE;
            Valve3 := FALSE;
            SeqDone := TRUE;
            SeqActive := FALSE;
            Timer1(IN := FALSE, PT := T#2s);
            Timer2(IN := FALSE, PT := T#2s);
            Timer3(IN := FALSE, PT := T#2s);
    END_CASE;
END_IF;
END_PROGRAM

PROGRAM SafetyInterlock
VAR_INPUT
    EStopOK : BOOL;
    GuardClosed : BOOL;
    ResetPB : BOOL;
END_VAR
VAR_OUTPUT
    MachineEnable : BOOL;
    SafetyFault : BOOL;
END_VAR
VAR
    ResetEdge : R_TRIG;
END_VAR

(* Detect rising edge of ResetPB *)
ResetEdge(CLK := ResetPB);

(* SafetyFault logic: set when EStop or Guard is open, reset on ResetPB edge when both are closed *)
IF (NOT EStopOK OR NOT GuardClosed) THEN
    SafetyFault := TRUE;
ELSIF ResetEdge.Q AND EStopOK AND GuardClosed THEN
    SafetyFault := FALSE;
END_IF;

(* MachineEnable logic *)
MachineEnable := NOT SafetyFault AND EStopOK AND GuardClosed;

END_PROGRAM

PROGRAM ProductionCounter
VAR_INPUT
    ProductSensor : BOOL;
    ResetBatch : BOOL;
    BatchTarget : INT := 1000;
END_VAR
VAR_OUTPUT
    BatchCount : INT;
    BatchComplete : BOOL;
    TotalCount : INT;
END_VAR
VAR
    SensorEdge : R_TRIG;
    Counter : CTU;
END_VAR

(* Detect rising edge of ProductSensor *)
SensorEdge(CLK := ProductSensor);

(* Batch counter: counts up to BatchTarget, resets on ResetBatch *)
Counter(CU := SensorEdge.Q, R := ResetBatch, PV := BatchTarget);

(* Assign outputs *)
BatchCount := Counter.CV;
BatchComplete := Counter.Q;

(* Total count increments on every rising edge *)
IF SensorEdge.Q THEN
    TotalCount := TotalCount + 1;
END_IF;

END_PROGRAM

FUNCTION_BLOCK MovingAverageFilter
VAR_INPUT
    enable : BOOL;
    rawInput : REAL;
    windowSize : INT;
END_VAR
VAR_OUTPUT
    filtered : REAL;
END_VAR
VAR
    buffer : ARRAY[0..9] OF REAL;
    head : INT := 0;
    count : INT := 0;
    sum : REAL := 0.0;
    effectiveSize : INT;
END_VAR

effectiveSize := LIMIT(1, windowSize, 10);

IF NOT enable THEN
    head := 0;
    count := 0;
    sum := 0.0;
    filtered := 0.0;
ELSE
    buffer[head] := rawInput;
    head := (head + 1) MOD effectiveSize;

    IF count < effectiveSize THEN
        count := count + 1;
    END_IF;

    sum := sum + rawInput;

    IF count = effectiveSize THEN
        sum := sum - buffer[head];
    END_IF;

    IF count > 0 THEN
        filtered := sum / INT_TO_REAL(count);
    ELSE
        filtered := 0.0;
    END_IF;
END_IF;

END_FUNCTION_BLOCK
